// ==========================================
// PR MANAGEMENT ROUTES
// ==========================================

// Invia candidatura PR
app.post('/api/pr/apply', authMiddleware, async (req, res) => {
    try {
        const { associationId } = req.body;
        if (!associationId) return res.status(400).json({ error: "Associazione non specificata" });

        const existing = await PRRequest.findOne({ userId: req.user.userId, associationId, status: 'pending' });
        if (existing) return res.status(400).json({ error: "Candidatura già inviata" });

        const request = await PRRequest.create({
            userId: req.user.userId,
            associationId,
            status: 'pending'
        });
        res.json(request);
    } catch (e) {
        res.status(500).json({ error: e.message });
    }
});

// Elenca richieste (Per l'Associazione)
app.get('/api/pr/requests', authMiddleware, async (req, res) => {
    try {
        if (req.user.role !== 'associazione') return res.status(403).json({ error: "Accesso negato" });
        const requests = await PRRequest.find({ associationId: req.user.userId, status: 'pending' }).populate('userId', 'name surname email profileImage');
        res.json(requests);
    } catch (e) {
        res.status(500).json({ error: e.message });
    }
});

// Gestione richiesta (Accetta/Rifiuta)
app.put('/api/pr/requests/:id', authMiddleware, async (req, res) => {
    try {
        if (req.user.role !== 'associazione') return res.status(403).json({ error: "Accesso negato" });
        const { status } = req.body;
        const request = await PRRequest.findById(req.params.id);

        if (!request || request.associationId.toString() !== req.user.userId) {
            return res.status(404).json({ error: "Richiesta non trovata" });
        }

        request.status = status;
        await request.save();

        if (status === 'accepted') {
            await User.findByIdAndUpdate(request.userId, {
                role: 'pr',
                parentOrganization: req.user.userId,
                isVerified: true
            });
        }
        res.json({ success: true });
    } catch (e) {
        res.status(500).json({ error: e.message });
    }
});

// Elenca PR Accreditati (Per l'Associazione)
app.get('/api/pr/list', authMiddleware, async (req, res) => {
    try {
        if (req.user.role !== 'associazione') return res.status(403).json({ error: "Accesso negato" });
        const prs = await User.find({ parentOrganization: req.user.userId, role: 'pr' });
        res.json(prs);
    } catch (e) {
        res.status(500).json({ error: e.message });
    }
});

// Statistiche PR (Per l'utente PR)
app.get('/api/pr/stats', authMiddleware, async (req, res) => {
    try {
        if (req.user.role !== 'pr') return res.status(403).json({ error: "Accesso negato" });

        const prUser = await User.findById(req.user.userId);
        const events = await Event.find({ organization: prUser.parentOrganization, status: 'active' });

        const stats = await Promise.all(events.map(async (event) => {
            const count = await Ticket.countDocuments({ event: event._id, prList: prUser.name, status: { $in: ['valid', 'entered', 'completed'] } });
            return {
                eventId: event._id,
                title: event.title,
                date: event.date,
                mySales: count
            };
        }));

        res.json(stats);
    } catch (e) {
        res.status(500).json({ error: e.message });
    }
});

