      api.auth.getAccreditedPRs().then(setAccreditedPRs);
      api.auth.getPRRequests().then(setPrRequests);
    }
  }, [user]);

  const handleTabChange = (tab: any) => {
      setActiveTab(tab);
      setSearchParams({ tab });
  };

