      markAsRead: async (id: string) => {
          const res = await fetch(`${API_URL}/notifications/${id}/read`, { method: 'PUT', headers: getHeaders() });
          return res.json();
      },
      getVapidKey: async () => {
          const res = await fetch(`${API_URL}/notifications/vapid-key`);
          return res.json();
      }
  }
};

